class Solution:
    def uniquePathsWithMemoization(self, grid: List[List[int]]) -> int:
        n, m = len(grid), len(grid[0])
        memo = {} # memo is a dictionary to store the number of unique paths from each cell to the top-left cell
        def dfs(i, j):
            # base case: if the cell is out of bounds, return 0
            if i < 0 or i >= n or j < 0 or j >= m:
                return 0
            # if the cell is the top-left cell, return 1
            if i == 0 and j == 0:
                return 1
            # if the cell is the same as the top-left cell, return 1
            if (i, j) in memo:
                return memo[(i, j)]
            # recursively count the number of unique paths
            memo[(i, j)] = dfs(i-1, j) + dfs(i, j-1)
            return memo[(i, j)]
        return dfs(n-1, m-1)
    # main function to call the dfs function
    def main(self):
        grid = [[1,1,1],[2,2,2],[3,3,3]]
        print(self.uniquePathsWithMemoization(grid))
if __name__ == '__main__':
    solution = Solution()
    solution.main()

